import base64
import json
import os
from google.cloud import storage, firestore, pubsub_v1
from google.cloud import secretmanager

def process_file(event, context):
    # Initialize clients
    storage_client = storage.Client()
    firestore_client = firestore.Client()
    publisher = pubsub_v1.PublisherClient()
    
    # Get the bucket and file name from the event
    bucket_name = event['bucket']
    file_name = event['name']
    
    # Validate input
    if not isinstance(bucket_name, str) or not isinstance(file_name, str):
        raise ValueError("Invalid bucket name or file name.")
    
    # Access the file
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    file_content = blob.download_as_text()
    
    # Process the file content (example: convert to JSON)
    try:
        data = json.loads(file_content)
    except json.JSONDecodeError:
        raise ValueError("File content is not valid JSON.")
    
    # Write to Firestore
    doc_ref = firestore_client.collection('your_collection').document(file_name)
    doc_ref.set(data)
    
    # Publish to Pub/Sub
    topic_name = 'your-topic'
    topic_path = publisher.topic_path('your-project-id', topic_name)
    message_json = json.dumps(data).encode('utf-8')
    publisher.publish(topic_path, message_json)
    
    return f"Processed file {file_name} from bucket {bucket_name}."